import{_ as e,a as i,b as n,c as d,d as t,e as l,f as r,g as o}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as s,o as u,c as p,a2 as k}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Other/federated-distributed-index.md","filePath":"id-ID/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),m={name:"id-ID/Other/federated-distributed-index.md"};function b(h,a,g,c,f,y){return u(),p("div",null,[...a[0]||(a[0]=[k('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index memungkinkan beberapa situs ImgBed saling berbagi daftar file.</p><p>Sederhananya:</p><ul><li>Anda bisa membagikan folder tertentu dari situs Anda ke pemilik node lain.</li><li>Anda bisa bergabung ke node lain dan menyinkronkan daftar file yang mereka bagikan ke panel admin Anda.</li><li>File federated terutama dipakai untuk dilihat, dicari, dan dibuka linknya. File tersebut tidak diupload ulang ke storage Anda sendiri.</li></ul><h2 id="lokasi-pengaturan" tabindex="-1">Lokasi Pengaturan <a class="header-anchor" href="#lokasi-pengaturan" aria-label="Permalink to &quot;Lokasi Pengaturan&quot;">​</a></h2><p>Buka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+e+`" alt="Local federation node" loading="lazy"></p><p>Halaman ini memiliki tiga tab:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Fungsi</th></tr></thead><tbody><tr><td>Local Node</td><td>Mengaktifkan node Anda, memastikan domain publik, memilih folder yang dibagikan, dan memperbarui outbound index</td></tr><tr><td>Nodes I Joined</td><td>Mengelola node ImgBed lain yang Anda ikuti</td></tr><tr><td>Nodes Joining Me</td><td>Mengelola permintaan dari pemilik lain yang ingin bergabung ke node Anda</td></tr></tbody></table><h2 id="setup-pertama-kali" tabindex="-1">Setup Pertama Kali <a class="header-anchor" href="#setup-pertama-kali" aria-label="Permalink to &quot;Setup Pertama Kali&quot;">​</a></h2><ol><li>Buka <code>Local Node</code>.</li><li>Aktifkan <code>Enable</code>.</li><li>Pilih folder yang ingin dibagikan di <code>Sync folders</code>.</li><li>Klik <code>Update Outbound Index</code>.</li><li>Jika ImgBed mendeteksi perubahan domain, pastikan domain saat ini sudah benar sebelum lanjut.</li></ol><p>Anda bisa memilih beberapa sync folder.</p><p>Jika daftar sync folder kosong, semua folder akan dibagikan.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain adalah URL situs yang dipakai node lain untuk mengakses node Anda.</p><p>ImgBed mendeteksinya otomatis. Anda tidak perlu mengetiknya manual. Saat pertama kali memperbarui index, ImgBed akan meminta konfirmasi apakah URL akses saat ini adalah domain produksi.</p><p>Jika domain berubah di kemudian hari, proses update index akan meminta konfirmasi lagi.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders menentukan file mana yang dibagikan ke federation nodes.</p><p>Misalnya Anda hanya memilih:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>Maka node lain hanya bisa melihat file di dua direktori tersebut.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Tombol ini memperbarui daftar file yang bisa disinkronkan node lain dari Anda.</p><p>Gunakan saat:</p><ul><li>Anda pertama kali mengaktifkan federation.</li><li>Anda mengupload file baru yang ingin dibagikan.</li><li>Anda mengubah sync folders.</li><li>Anda mengubah public domain dan perlu mengonfirmasinya.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> adalah tempat Anda berlangganan ke node lain.</p><p><img src="`+i+'" alt="Nodes I joined" loading="lazy"></p><h3 id="meminta-bergabung-ke-node-lain" tabindex="-1">Meminta Bergabung ke Node Lain <a class="header-anchor" href="#meminta-bergabung-ke-node-lain" aria-label="Permalink to &quot;Meminta Bergabung ke Node Lain&quot;">​</a></h3><ol><li>Minta invitation link kepada pemilik node tersebut.</li><li>Tempelkan link ke kotak input.</li><li>Klik <code>Request to Join</code>.</li><li>Tunggu pemilik node menyetujui permintaan di panel admin mereka.</li></ol><p>Setelah disetujui, status node akan menjadi approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> menyinkronkan daftar file dari node yang Anda ikuti.</p><p>Gunakan saat:</p><ul><li>Pemilik node baru saja menyetujui permintaan Anda.</li><li>Pemilik node memberi tahu bahwa konten yang dibagikan sudah diperbarui.</li><li>Anda ingin menyegarkan semua daftar file federation yang diikuti.</li></ul><p>Untuk memperbarui satu node saja, klik <code>Update Index</code> pada card node tersebut.</p><p><img src="'+n+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>Jika tidak ingin lagi menyinkronkan node tertentu, klik <code>Unsubscribe</code>.</p><p>Setelah unsubscribe, federated index dari node tersebut akan dihapus dari situs lokal Anda.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> adalah tempat menangani permintaan dari pemilik lain.</p><p><img src="'+d+'" alt="Nodes joining me" loading="lazy"></p><h3 id="membuat-invitation-link" tabindex="-1">Membuat Invitation Link <a class="header-anchor" href="#membuat-invitation-link" aria-label="Permalink to &quot;Membuat Invitation Link&quot;">​</a></h3><ol><li>Pastikan local node sudah aktif.</li><li>Klik <code>Update Outbound Index</code> setidaknya sekali agar ImgBed mengonfirmasi public domain.</li><li>Buka <code>Nodes Joining Me</code>.</li><li>Klik <code>Reset Invitation Link</code>.</li><li>Salin invitation link dan kirim ke pemilik node lain.</li></ol><p>Jika invitation link kosong, biasanya public domain belum dikonfirmasi. Kembali ke <code>Local Node</code>, lalu klik <code>Update Outbound Index</code>.</p><h3 id="menangani-permintaan-bergabung" tabindex="-1">Menangani Permintaan Bergabung <a class="header-anchor" href="#menangani-permintaan-bergabung" aria-label="Permalink to &quot;Menangani Permintaan Bergabung&quot;">​</a></h3><p>Saat seseorang mengirim permintaan, permintaan tersebut muncul di daftar <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Aksi</th><th>Arti</th></tr></thead><tbody><tr><td>Approve</td><td>Mengizinkan node lain menyinkronkan daftar file yang Anda bagikan</td></tr><tr><td>Reject</td><td>Menolak permintaan bergabung</td></tr><tr><td>Delete</td><td>Menghapus catatan yang sudah selesai</td></tr><tr><td>Check Status</td><td>Mengecek apakah pihak lain masih mempertahankan hubungan ini</td></tr></tbody></table><p>Setelah Anda menyetujui, pihak lain tetap perlu mengklik <code>Update Inbound Index</code> sebelum file yang Anda bagikan muncul di sisi mereka.</p><p><img src="'+t+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>Setelah hubungan disetujui, klik <code>Message</code> pada card node.</p><p>Pesan hanya dipakai untuk komunikasi tentang hubungan federation. Pesan tidak mengubah file, tag, direktori, atau permission.</p><p><img src="'+l+'" alt="Messages" loading="lazy"></p><h2 id="melihat-federated-files" tabindex="-1">Melihat Federated Files <a class="header-anchor" href="#melihat-federated-files" aria-label="Permalink to &quot;Melihat Federated Files&quot;">​</a></h2><p>Setelah sinkronisasi selesai, kembali ke daftar file di admin.</p><p>Di bagian atas halaman, pindah antara local files dan federated files. Pada federated files, Anda bisa melihat konten yang sudah disinkronkan.</p><p>Federated files terutama dipakai untuk melihat, mencari, preview, dan menyalin link. Karena bukan file lokal, Anda tidak bisa memindahkan, menghapus, mengganti tag, atau membackupnya dari situs sendiri.</p><p><img src="'+r+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="kenapa-diminta-mengajukan-ulang-karena-tidak-ada-relationship-record" tabindex="-1">Kenapa Diminta Mengajukan Ulang Karena Tidak Ada Relationship Record? <a class="header-anchor" href="#kenapa-diminta-mengajukan-ulang-karena-tidak-ada-relationship-record" aria-label="Permalink to &quot;Kenapa Diminta Mengajukan Ulang Karena Tidak Ada Relationship Record?&quot;">​</a></h3><p>Biasanya ini berarti pihak lain sudah menghapus Anda beserta catatannya, sehingga hubungan tidak lagi ditemukan. Kirim permintaan bergabung baru.</p><p><img src="'+o+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="kenapa-file-tidak-terlihat-setelah-bergabung" tabindex="-1">Kenapa File Tidak Terlihat Setelah Bergabung? <a class="header-anchor" href="#kenapa-file-tidak-terlihat-setelah-bergabung" aria-label="Permalink to &quot;Kenapa File Tidak Terlihat Setelah Bergabung?&quot;">​</a></h3><p>Periksa:</p><ol><li>Pemilik node lain sudah menyetujui permintaan Anda.</li><li>Pemilik node lain sudah mengklik <code>Update Outbound Index</code>.</li><li>Anda sudah mengklik <code>Update Inbound Index</code>.</li><li>Sync folders milik pemilik node lain memang mencakup direktori yang ingin mereka bagikan.</li></ol><h3 id="apa-yang-harus-dilakukan-jika-terdeteksi-perubahan-domain" tabindex="-1">Apa yang Harus Dilakukan Jika Terdeteksi Perubahan Domain? <a class="header-anchor" href="#apa-yang-harus-dilakukan-jika-terdeteksi-perubahan-domain" aria-label="Permalink to &quot;Apa yang Harus Dilakukan Jika Terdeteksi Perubahan Domain?&quot;">​</a></h3><p>Jika Anda sedang membuka panel admin melalui domain produksi, konfirmasi dan lanjutkan.</p><p>Jika memakai alamat sementara, batalkan dulu, buka ulang panel admin dengan domain produksi, lalu coba lagi.</p><h3 id="apa-arti-daftar-sync-folder-kosong" tabindex="-1">Apa Arti Daftar Sync Folder Kosong? <a class="header-anchor" href="#apa-arti-daftar-sync-folder-kosong" aria-label="Permalink to &quot;Apa Arti Daftar Sync Folder Kosong?&quot;">​</a></h3><p>Daftar sync folder kosong berarti semua folder dibagikan.</p><p>Untuk membagikan hanya sebagian direktori, pilih folder tersebut secara manual.</p><h3 id="perbedaan-outbound-dan-inbound-index-update" tabindex="-1">Perbedaan Outbound dan Inbound Index Update <a class="header-anchor" href="#perbedaan-outbound-dan-inbound-index-update" aria-label="Permalink to &quot;Perbedaan Outbound dan Inbound Index Update&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tombol</th><th>Arti Sederhana</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Memperbarui data yang bisa disinkronkan orang lain dari saya</td></tr><tr><td>Update Inbound Index</td><td>Memperbarui data yang saya sinkronkan dari orang lain</td></tr></tbody></table>',78)])])}const I=s(m,[["render",b]]);export{P as __pageData,I as default};
